import { readFileSync } from 'node:fs';
import { join } from 'node:path';
import { setJsonMode, isJsonMode, printJSON, printHuman } from './utils/output';
import { detectPackageManager } from './detect';
import { install } from './commands/install';
import { remove } from './commands/remove';
import { run } from './commands/run';
import { exec } from './commands/exec';
import { upgrade } from './commands/upgrade';
import { clean } from './commands/clean';
import { init } from './commands/init';

const VERSION = JSON.parse(readFileSync(join(__dirname, '..', 'package.json'), 'utf8')).version;

function printHelp(): void {
    const detection = detectPackageManager();

    if (isJsonMode()) {
        printJSON({
            name: 'bi',
            version: VERSION,
            commands: [
                { name: 'i', aliases: ['install', 'add'], usage: 'bi i [pkg...]', desc: 'Install dependencies' },
                { name: 'rm', aliases: ['remove', 'un', 'uninstall'], usage: 'bi rm <pkg...>', desc: 'Remove dependencies' },
                { name: 'run', aliases: ['dev', 'build', 'test', 'start'], usage: 'bi run <script>', desc: 'Run a script' },
                { name: 'x', aliases: ['exec'], usage: 'bi x <pkg>', desc: 'Execute a package' },
                { name: 'up', aliases: ['upgrade', 'update'], usage: 'bi up', desc: 'Upgrade outdated deps' },
                { name: 'clean', aliases: ['purge'], usage: 'bi clean', desc: 'Delete node_modules and caches' },
                { name: 'init', aliases: [], usage: 'bi init', desc: 'Scaffold a new project' },
            ],
            detected_pm: { pm: detection.pm, reason: detection.reason },
        });
        return;
    }

    console.log(`
  bi v${VERSION} — The 2-letter dev toolkit. Type less, do more.

  Usage: bi <command> [options]

  Commands:
    bi i [pkg...]         Install dependencies (aliases: install, add)
    bi rm <pkg...>        Remove dependencies (aliases: remove, un)
    bi run <script>       Run a script (shortcuts: bi dev, bi build, bi test)
    bi x <pkg> [args]     Execute a package (alias: exec)
    bi up                 Check and upgrade outdated dependencies
    bi clean              Delete node_modules and caches
    bi init               Scaffold a new project

  Global Flags:
    -h, --help            Show this help message
    -v, --version         Show version number
    --json                Output as JSON (for AI agents)

  Detected: ${detection.pm} (${detection.reason}${detection.lockfile ? `: ${detection.lockfile}` : ''})
`);
}

function parseArgs(argv: string[]): { command: string; args: string[]; flags: Record<string, boolean> } {
    const flags: Record<string, boolean> = {};
    const positional: string[] = [];

    for (const arg of argv) {
        if (arg === '--json') flags.json = true;
        else if (arg === '--help' || arg === '-h') flags.help = true;
        else if (arg === '--version' || arg === '-v') flags.version = true;
        else if (arg === '-D' || arg === '--dev') flags.dev = true;
        else if (arg === '-g' || arg === '--global') flags.global = true;
        else if (arg === '--dry-run') flags.dryRun = true;
        else if (arg === '--apply') flags.apply = true;
        else if (arg.startsWith('--template=')) {
            flags._template = true;
            positional.push(arg); // keep for template extraction
        }
        else positional.push(arg);
    }

    return {
        command: positional[0] || '',
        args: positional.slice(1),
        flags,
    };
}

function extractTemplate(args: string[]): string | undefined {
    for (const arg of args) {
        if (arg.startsWith('--template=')) return arg.split('=')[1];
    }
    return undefined;
}

async function main(): Promise<void> {
    const rawArgs = process.argv.slice(2);
    const { command, args, flags } = parseArgs(rawArgs);

    // Set global JSON mode
    if (flags.json) setJsonMode(true);

    // Global flags take priority
    if (flags.version) {
        if (isJsonMode()) {
            printJSON({ name: 'bi', version: VERSION });
        } else {
            console.log(`bi@${VERSION}`);
        }
        process.exit(0);
    }

    if (flags.help || !command) {
        printHelp();
        process.exit(0);
    }

    // Command routing
    const SCRIPT_SHORTCUTS = ['dev', 'build', 'test', 'start'];
    let exitCode = 0;

    try {
        switch (command) {
            case 'i':
            case 'install':
            case 'add': {
                const result = await install(args, { dev: flags.dev, global: flags.global });
                exitCode = result.exitCode;
                break;
            }
            case 'rm':
            case 'remove':
            case 'un':
            case 'uninstall': {
                const result = await remove(args, {});
                exitCode = result.exitCode;
                break;
            }
            case 'run': {
                const result = await run(args[0] || '', args.slice(1), {});
                exitCode = result.exitCode;
                break;
            }
            case 'x':
            case 'exec': {
                const result = await exec(args[0] || '', args.slice(1), {});
                exitCode = result.exitCode;
                break;
            }
            case 'up':
            case 'upgrade':
            case 'update': {
                await upgrade({ apply: flags.apply });
                break;
            }
            case 'clean':
            case 'purge': {
                await clean({ dryRun: flags.dryRun });
                break;
            }
            case 'init': {
                const template = extractTemplate(rawArgs);
                const result = await init({ template });
                exitCode = result.exitCode;
                break;
            }
            default: {
                if (SCRIPT_SHORTCUTS.includes(command)) {
                    // shortcut: bi dev → bi run dev
                    const result = await run(command, args, {});
                    exitCode = result.exitCode;
                } else {
                    printHuman(`Unknown command: ${command}. Run 'bi --help'.`, 'error');
                    exitCode = 1;
                }
            }
        }
    } catch (err) {
        const message = err instanceof Error ? err.message : String(err);
        if (isJsonMode()) {
            printJSON({ error: message });
        } else {
            printHuman(message, 'error');
        }
        exitCode = 1;
    }

    process.exit(exitCode);
}

main();
